sys_script_include.script:
var TableWidgetStateBuilder = Class.create();
TableWidgetStateBuilder.prototype = {
    initialize: function (options) {
        options = options || {};
        this.widgetHelper = options.widgetHelper;
        this.normalizer =
            options.normalizer ||
            new TableContractNormalizer({ logger: options.logger });
        this.logger = options.logger;
    },

    buildInitialState: function () {
        var widgetHelper = this.widgetHelper;
        var normalizer = this.normalizer;

        if (!widgetHelper) {
            return {};
        }

        var state = {
            title: widgetHelper.getPageTitle(),
            showNewRecordButton: widgetHelper.canCreate(),
            detailViewPage: widgetHelper.getDetailViewPage(),
            idField: widgetHelper.getIdField(),
            canFilter: widgetHelper.canFilter(),
            filterFields: normalizer.buildUnifiedFilterFields(
                widgetHelper.getAllAvailableColumns(),
                widgetHelper.getFilterFields(),
            ),
            limit: widgetHelper.getTableLimit(),
            canSavePreferences: widgetHelper.canSavePreferences(),
            allColumnsAvailable: widgetHelper.getAllAvailableColumns(),
            columns: normalizer.normalizeColumns(
                widgetHelper.getTableColumns(),
            ),
            canConfigureColumns: widgetHelper.canConfigureColumns(),
            showMetadata: widgetHelper.showTableMetadata(),
            showAppliedFilters: widgetHelper.showAppliedFilters(),
            rowClickAction:
                typeof widgetHelper.getRowClickAction === "function"
                    ? widgetHelper.getRowClickAction()
                    : { target: "none", action: {} },
            hasContextMenu:
                typeof widgetHelper.getContextMenuItems === "function",
            canSaveFilters:
                typeof widgetHelper.canSaveFilters === "function"
                    ? widgetHelper.canSaveFilters()
                    : typeof widgetHelper.getSavedFilters === "function",
            defaultAppliedFilters:
                typeof widgetHelper.getDefaultAppliedFilters === "function"
                    ? widgetHelper.getDefaultAppliedFilters() || []
                    : [],
        };

        // Disable filtering if no filter fields are available.
        if (state.canFilter && state.filterFields.length === 0) {
            state.canFilter = false;
        }

        return state;
    },

    type: "TableWidgetStateBuilder",
};
